export default {
  lookup(u) {
    // Latin-1 is one-to-one mapping
    if (u >= 0x20 && u <= 0xff) {
      return u;
    }

    // Lookup table (fairly random)
    const keysym = codepoints[u];
    if (keysym !== undefined) {
      return keysym;
    }

    // General mapping as the final fallback
    return 0x01000000 | u;
  },
};
